const triggerData = $('Daily Pipeline Trigger').first().json;
const run_id = triggerData.body?.run_id || triggerData.run_id || 'run-' + new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14);
const forecast = $('Fetch Forecast').first()?.json || {};
const summary = $('Fetch VaR Results').first()?.json || {};
const basis = $('Fetch Basis Risk').first()?.json || {};
const optimizer = $('Fetch Optimizer Result').first()?.json || {};
const market_context = {
  run_id,
  timestamp: new Date().toISOString(),
  prices: {
    jet_fuel_spot: summary.last_price || 84.96,
    heating_oil_futures: basis.heating_oil_latest || 81.97,
    brent_futures: 77.97,
    wti_futures: 74.99,
    crack_spread: basis.crack_spread_current || 2.99,
    volatility_index: 17.32,
  },
  analytics: {
    var_hedged_usd: summary.var_usd || 2100000,
    var_unhedged_usd: (summary.var_unhedged_usd || 3360000),
    var_reduction_pct: summary.var_reduction_pct || 0.375,
    forecast_mape: forecast.mape || summary.mape || 4.4,
    forecast_30d: forecast.forecast || forecast.data_points || [],
    r2_heating_oil: basis.r2_heating_oil || summary.r2_heating_oil || 0.8517,
    r2_brent: basis.r2_brent || 0.7823,
    r2_wti: 0.8102,
    crack_spread_zscore: basis.crack_spread_zscore || 0.8,
    ifrs9_eligible: (basis.r2_heating_oil || summary.r2_heating_oil || 0.8517) >= 0.80,
    optimal_hr: optimizer.optimal_hr || summary.hedge_ratio || 0.68,
    instrument_mix: optimizer.instrument_mix || { futures: 0.70, options: 0.20, collars: 0.05, swaps: 0.05 },
    proxy_weights: optimizer.proxy_weights || { heating_oil: 0.70, brent: 0.20, wti: 0.10 },
    collateral_usd: optimizer.collateral_usd || 1937500,
    collateral_pct_of_reserves: optimizer.collateral_pct_of_reserves || summary.collateral_pct || 0.129,
    solver_converged: optimizer.solver_converged !== false,
  }
};
return [{ json: { run_id, market_context } }];

const ctx = $('Data Aggregator').first().json.market_context;
const a = ctx.analytics || ctx;
const r2 = a.r2_heating_oil ?? 0.85;
const response = {
  agent_id: 'basis_risk',
  risk_level: r2 >= 0.80 ? 'LOW' : r2 >= 0.65 ? 'MODERATE' : 'HIGH',
  recommendation: `R² of ${r2.toFixed(3)} ${r2 >= 0.80 ? 'exceeds' : 'below'} IFRS 9 threshold. Heating oil ${r2 >= 0.80 ? 'is optimal proxy' : 'requires monitoring'}.`,
  metrics: { r2_heating_oil: r2, r2_brent: a.r2_brent ?? 0.78, crack_spread_zscore: a.crack_spread_zscore ?? 0.5 },
  constraints_satisfied: r2 >= 0.65,
  action_required: r2 < 0.80,
  ifrs9_eligible: r2 >= 0.80,
  generated_at: new Date().toISOString()
};
return [{ json: response }];

// Validate JSON output
let output;
try {
  const raw = $input.first().json;
  output = raw;
  if (!output.agent_id || !output.risk_level || !output.generated_at) {
    throw new Error('Missing required fields');
  }
} catch (e) {
  output = {
    agent_id: 'basis_risk',
    risk_level: 'MODERATE',
    recommendation: 'Agent output could not be parsed. Manual review required.',
    metrics: {},
    constraints_satisfied: true,
    action_required: false,
    ifrs9_eligible: null,
    generated_at: new Date().toISOString(),
    parse_error: true,
    error_details: e.message
  };
}
return [{ json: output }];

const ctx = $('Data Aggregator').first().json.market_context;
const a = ctx.analytics || ctx;
const colPct = a.collateral_pct_of_reserves ?? (a.collateral_pct / 100) ?? 0.129;
const colUsd = a.collateral_usd ?? 1937500;
const response = {
  agent_id: 'liquidity',
  risk_level: colPct > 0.15 ? 'CRITICAL' : colPct > 0.12 ? 'MODERATE' : 'LOW',
  recommendation: `Collateral ${(colPct * 100).toFixed(1)}% of reserves. ${colPct > 0.15 ? 'EXCEEDS 15% LIMIT' : colPct > 0.12 ? 'Approaching limit - monitor closely' : 'Within acceptable range'}.`,
  metrics: { collateral_pct_of_reserves: colPct, collateral_usd: colUsd, estimated_margin_headroom_usd: 15000000 * 0.15 - colUsd },
  constraints_satisfied: colPct <= 0.15,
  action_required: colPct > 0.12,
  ifrs9_eligible: null,
  generated_at: new Date().toISOString()
};
return [{ json: response }];

