const a = ctx.analytics || ctx;
const hr = a.optimal_hr ?? 0.68;
const response = {
  agent_id: 'operational',
  risk_level: hr > 0.80 ? 'CRITICAL' : hr > 0.75 ? 'MODERATE' : 'LOW',
  recommendation: `Hedge ratio ${(hr * 100).toFixed(1)}% ${hr > 0.80 ? 'EXCEEDS 80% HARD CAP' : 'is within operational limits'}.`,
  metrics: { optimal_hr: hr, hr_hard_cap: 0.80, coverage_ratio_estimate: hr / 0.80 },
  constraints_satisfied: hr <= 0.80,
  action_required: hr > 0.75,
  ifrs9_eligible: null,
  generated_at: new Date().toISOString()
};
return [{ json: response }];

