const a = ctx.analytics || ctx;
const r2 = a.r2_heating_oil ?? 0.85;
const response = {
  agent_id: 'ifrs9',
  risk_level: r2 >= 0.80 ? 'LOW' : r2 >= 0.65 ? 'HIGH' : 'CRITICAL',
  recommendation: `${r2 >= 0.80 ? 'IFRS 9 ELIGIBLE' : 'IFRS 9 INELIGIBLE'}. R² ${r2.toFixed(3)} ${r2 >= 0.80 ? 'meets' : 'below'} 0.80 threshold.`,
  metrics: { r2_prospective: r2, ifrs9_eligible: r2 >= 0.80, retrospective_ratio_estimate: 0.96 },
  constraints_satisfied: r2 >= 0.65,
  action_required: r2 < 0.80,
  ifrs9_eligible: r2 >= 0.80,
  generated_at: new Date().toISOString()
};
