  };
}
return [{ json: output }];

const ctx = $('Data Aggregator').first().json.market_context;
const vol = ctx.prices?.volatility_index ?? 17.32;
const volRegime = vol < 15 ? 'LOW' : vol < 25 ? 'MODERATE' : 'HIGH';
const response = {
  agent_id: 'macro',
  risk_level: vol < 15 ? 'LOW' : vol < 25 ? 'MODERATE' : 'HIGH',
  recommendation: `Volatility ${vol.toFixed(1)}. ${vol >= 25 ? 'Consider increasing hedge ratio' : 'Neutral macro - proceed with recommended hedge'}.`,
  metrics: { volatility_index: vol, vol_regime: volRegime, geopolitical_risk: 'MODERATE', hedge_timing_signal: vol >= 25 ? 'WAIT' : 'HEDGE_NOW' },
  constraints_satisfied: true,
  action_required: vol >= 25,
  ifrs9_eligible: null,
  generated_at: new Date().toISOString()
};
return [{ json: response }];

// Validate JSON output
let output;
try {
  const raw = $input.first().json;
  output = raw;
  if (!output.agent_id || !output.risk_level || !output.generated_at) {
    throw new Error('Missing required fields');
  }
} catch (e) {
  output = {
    agent_id: 'macro',
    risk_level: 'MODERATE',
    recommendation: 'Agent output could not be parsed. Manual review required.',
    metrics: {},
    constraints_satisfied: true,
    action_required: false,
    ifrs9_eligible: null,
    generated_at: new Date().toISOString(),
    parse_error: true,
    error_details: e.message
  };
}
return [{ json: output }];

const items = $input.all();
const agentOrder = ['basis_risk', 'liquidity', 'operational', 'ifrs9', 'macro'];
const agents = agentOrder.map(id => items.find(i => i.json.agent_id === id)?.json).filter(Boolean);
const fallback = { agent_id: 'unknown', risk_level: 'MODERATE', recommendation: 'Missing', metrics: {}, constraints_satisfied: true, action_required: false, ifrs9_eligible: null, generated_at: new Date().toISOString() };
while (agents.length < 5) agents.push({ ...fallback, agent_id: agentOrder[agents.length] });
const ctx = $('Data Aggregator').first().json.market_context;
const a = ctx.analytics || ctx;
const hr = a.optimal_hr ?? 0.68;
const riskCounts = {LOW: 0, MODERATE: 0, HIGH: 0, CRITICAL: 0};
agents.forEach(ag => riskCounts[ag.risk_level]++);
let consensusRisk = 'LOW';
if (riskCounts.CRITICAL > 0) consensusRisk = 'CRITICAL';
else if (riskCounts.HIGH > 0) consensusRisk = 'HIGH';
else if (riskCounts.MODERATE >= 2) consensusRisk = 'MODERATE';
const mix = a.instrument_mix || { futures: 0.7, options: 0.2, collars: 0.05, swaps: 0.05 };
const topInst = Object.entries(mix).sort((x,y)=>y[1]-x[1])[0]?.[0] || 'futures';
const keyConcerns = agents.filter(ag => ag.risk_level === 'HIGH' || ag.risk_level === 'CRITICAL').map(ag => (ag.recommendation || '').slice(0, 100)).slice(0, 5);
const committee = { top_strategy: 'Hedge ' + Math.round(hr*100) + '% using ' + topInst, consensus_risk_level: consensusRisk, key_concerns: keyConcerns.length > 0 ? keyConcerns : ['All agents report normal operating conditions'], recommended_hr: hr, rationale: agents.filter(ag => ag.constraints_satisfied).length + '/5 approve. ' + consensusRisk + ' risk.', agents };
return [{ json: committee }];

const data = $('Committee Synthesizer').first().json;
const agents = data.agents || [];
const ctx = $('Data Aggregator').first().json.market_context;
const a = ctx.analytics || ctx;
const hr = a.optimal_hr ?? 0.68;
const colPct = a.collateral_pct_of_reserves ?? 0.129;
let approved = true;
let blockingReason = null;
if (agents.some(x => x.constraints_satisfied === false)) { approved = false; blockingReason = 'One or more agents flagged constraint violations'; }
if (hr > 0.80) { approved = false; blockingReason = (blockingReason ? blockingReason + '; ' : '') + 'HR exceeds 80% cap'; }
if (colPct > 0.15) { approved = false; blockingReason = (blockingReason ? blockingReason + '; ' : '') + 'Collateral exceeds 15%'; }
return [{ json: { ...data, cro_decision: { approved_for_presentation: approved, blocking_reason: blockingReason, final_risk_level: data.consensus_risk_level } } }];

const data = $('CRO Risk Gate').first().json;
const ctx = $('Data Aggregator').first().json.market_context;
const mc = ctx.analytics || ctx;
const { agents, ...committeeConsensus } = data;
const payload = {
  run_id: ctx.run_id,
  triggered_at: new Date().toISOString(),
  optimal_hr: mc.optimal_hr ?? 0.68,
  instrument_mix: mc.instrument_mix || { futures: 0.70, options: 0.20, collars: 0.05, swaps: 0.05 },
  proxy_weights: mc.proxy_weights || { heating_oil: 0.70, brent: 0.20, wti: 0.10 },
  var_hedged_usd: mc.var_hedged_usd ?? 2100000,
  var_unhedged_usd: mc.var_unhedged_usd ?? 3360000,
  var_reduction_pct: mc.var_reduction_pct ?? 0.375,
  collateral_usd: mc.collateral_usd ?? 1937500,
  collateral_pct_of_reserves: mc.collateral_pct_of_reserves ?? 0.129,
  solver_converged: mc.solver_converged !== false,
  agent_outputs: agents || [],
  committee_consensus: committeeConsensus,
  cro_decision: data.cro_decision
};
return [{ json: payload }];

const response = $input.first().json;
const ctx = $('Data Aggregator').first().json.market_context;

console.log('✅ WORKFLOW COMPLETE');
console.log('Run ID:', ctx.run_id);
console.log('FastAPI Response:', JSON.stringify(response, null, 2));

return [{
  json: {
    workflow_status: 'SUCCESS',
    run_id: ctx.run_id,
    recommendation_id: response.id || null,
    completed_at: new Date().toISOString()
  }
}];
